struct DataResult {
    uint8_t data_type;
    std::vector<uint32_t> int_items;
    std::vector<float> float_items;
};

DataResult preview_and_read_data(const std::span<const uint8_t> buffer) {
    // Create a buffer_adaptor for the input span
    hexi::buffer_adaptor<const std::span<const uint8_t>> adaptor(buffer);

    // Create a binary_stream using the buffer_adaptor
    hexi::binary_stream<decltype(adaptor)> stream(adaptor);

    DataResult result;

    // Preview the data_type (first byte) using view() without advancing the read pointer
    // Since view() returns a string_view and advances the pointer, we need to use operator[]
    // to peek at the first byte without advancing
    result.data_type = static_cast<uint8_t>(stream[0]);

    // Check if sufficient data exists for the entire structure
    uint32_t item_count;
    stream >> item_count;  // Read item_count

    // Calculate required size: 1 byte (data_type) + 4 bytes (item_count) + (item_count * item_size)
    size_t item_size = (result.data_type == 0) ? sizeof(uint32_t) : sizeof(float);
    size_t total_required_size = 1 + 4 + (item_count * item_size);

    // Verify we have enough data
    if (buffer.size() < total_required_size) {
        return result;  // Return partial result if insufficient data
    }

    // Read the items based on the data type
    if (result.data_type == 0) {
        // Integers case
        result.int_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.int_items[i];
        }
    } else {
        // Floats case
        result.float_items.resize(item_count);
        for (uint32_t i = 0; i < item_count; ++i) {
            stream >> result.float_items[i];
        }
    }

    return result;
}
