#include <hexi/allocators/block_allocator.h>
#include <cstdint>

// Note: push() and pop() are private, but we can observe their behavior
// through allocate() and deallocate() operations
template<size_t element_count = 10>
void demonstrate_block_allocator_behavior() {
    // Create a block_allocator for uint8_t with the specified element count
    hexi::block_allocator<uint8_t, element_count> allocator;

    // Demonstrate allocation (which internally calls pop() from free list)
    uint8_t* block1 = allocator.allocate();
    uint8_t* block2 = allocator.allocate();

    // Demonstrate deallocation (which internally calls push() to free list)
    allocator.deallocate(block1);
    allocator.deallocate(block2);

    // Additional demonstration: allocate all blocks and then deallocate them
    uint8_t* blocks[element_count];
    for (size_t i = 0; i < element_count; ++i) {
        blocks[i] = allocator.allocate();
    }

    for (size_t i = 0; i < element_count; ++i) {
        allocator.deallocate(blocks[i]);
    }
}
```

This implementation demonstrates the internal push/pop operations by:

1. Creating a `block_allocator` instance for `uint8_t` with the specified element count
2. Using `allocate()` to remove blocks from the free list (internally calling `pop()`)
3. Using `deallocate()` to return blocks to the free list (internally calling `push()`)
4. Showing both single and batch allocation/deallocation patterns

The behavior follows the internal mechanics:
- `allocate()` calls `pop()` to get the head of the free list
- `deallocate()` calls `push()` to add to the head of the free list
- The constructor pre-populates the free list with `element_count` blocks
- Each allocation consumes a block from the free list
- Each deallocation returns a block to the free list

This demonstrates the circular nature of the free list management where blocks are linked together and managed via head insertion/removal operations.

