std::vector<uint8_t> preview_data_without_consuming(const hexi::detail::intrusive_storage<block_size>& storage, size_t bytes_to_preview) {
    // Create destination buffer with appropriate size
    std::vector<uint8_t> preview_buffer(bytes_to_preview);

    // Use the copy function to preview data without advancing read pointer
    // The copy function handles the case where bytes_to_preview exceeds available data
    std::size_t bytes_copied = storage.copy(preview_buffer.data(), bytes_to_preview);

